"""
terrarium_show — display images from Python code in the Terrarium Python Runner's View tab.

Usage:
    import terrarium_show

    # matplotlib
    import matplotlib.pyplot as plt
    plt.plot([1, 2, 3, 2, 5])
    terrarium_show.show(plt.gcf())

    # PIL / Pillow
    from PIL import Image
    img = Image.open("photo.png")
    terrarium_show.show(img)

    # raw bytes (already encoded as PNG / JPEG)
    with open("chart.png", "rb") as f:
        terrarium_show.show(f.read())

How it works:
    `show(...)` base64-encodes the image and prints a single line of the form
        __TERRARIUM_IMG_PNG_B64__:<base64-data>
    The Terrarium Python Runner sheet scans stdout for these lines, decodes them
    into PNG data, displays them in the View tab, and hides the marker lines
    from the Console tab.
"""

from __future__ import annotations

import base64
import io
import sys


MARKER = "__TERRARIUM_IMG_PNG_B64__:"


def _to_png_bytes(obj) -> bytes:
    """Coerce common image-like objects to PNG bytes."""
    # matplotlib Figure / Axes — anything with `.savefig`
    if hasattr(obj, "savefig"):
        buf = io.BytesIO()
        obj.savefig(buf, format="png", bbox_inches="tight", dpi=150)
        buf.seek(0)
        return buf.read()

    # PIL / Pillow Image — anything with `.save`
    if hasattr(obj, "save") and hasattr(obj, "size"):
        buf = io.BytesIO()
        obj.save(buf, format="PNG")
        buf.seek(0)
        return buf.read()

    # raw bytes
    if isinstance(obj, (bytes, bytearray, memoryview)):
        return bytes(obj)

    raise TypeError(
        f"terrarium_show.show() doesn't know how to display {type(obj).__name__}; "
        f"pass a matplotlib Figure, a PIL Image, or raw PNG/JPEG bytes."
    )


def show(image) -> None:
    """Display `image` in the Python Runner's View tab.

    Accepts a matplotlib Figure, a PIL Image, or raw bytes.
    Emits the marker on its own line so the Swift side can isolate it
    even if other prints happen on the same line.
    """
    data = _to_png_bytes(image)
    encoded = base64.b64encode(data).decode("ascii")
    # Leading + trailing newlines guarantee the marker is on its own line
    # so the Swift parser can split cleanly.
    sys.stdout.write(f"\n{MARKER}{encoded}\n")
    sys.stdout.flush()


def show_bytes(data: bytes) -> None:
    """Display raw PNG/JPEG `data` directly. Convenience for users who
    don't want the auto-detection in `show`."""
    show(bytes(data))
